function automatic logic[3:0] ids_t[2:0][1:0] gen_stage_ids();
  for (int unsigned st=0; st<3; st++)
    for (int unsigned id=0; id<2; id++)
      gen_stage_ids[st][id] = SRC_ID + st * 2 + id;
endfunction
localparam logic[3:0] STAGE_IDS[2:0][1:0] = gen_stage_ids();

parameter int unsigned N_STAGES = 4;
parameter int unsigned N_STAGE_IDS = 2;
generate
  for (genvar i=1; i<N_STAGES; i++)
    for (genvar j=i; j<N_STAGES; j++)
      for (genvar k=0; k<N_STAGE_IDS; k++)
        assign match_id[(j-i)*N_STAGE_IDS+k] = out_id[i-1]==STAGE_IDS[j][k];
endgenerate
